class DeepLinkHandler {
  static final DeepLinkHandler _instance = DeepLinkHandler._internal();
  factory DeepLinkHandler() => _instance;
  DeepLinkHandler._internal();

  StreamSubscription? _linkSubscription;
  BuildContext? _context;

  void initialize(BuildContext context) {
    _context = context;
    _handleInitialLink();
    _handleIncomingLinks();
  }

  Future<void> _handleInitialLink() async {
    try {
      final initialLink = await getInitialLink();
      if (initialLink != null) {
        _processDeepLink(initialLink);
      }
    } on PlatformException catch (e) {
      print('Failed to get initial link: ${e.message}');
    } on FormatException catch (e) {
      print('Invalid link format: ${e.message}');
    }
  }

  void _handleIncomingLinks() {
    _linkSubscription = linkStream.listen(
      (String? link) {
        if (link != null) {
          _processDeepLink(link);
        }
      },
      onError: (err) {
        print('Error handling deep link: $err');
      },
    );
  }

  void _processDeepLink(String link) {
    if (_context == null) return;

    final uri = Uri.parse(link);
    
    if (uri.scheme != 'myapp') {
      print('Invalid scheme: ${uri.scheme}');
      return;
    }

    final pathSegments = uri.pathSegments;
    final queryParams = uri.queryParameters;

    if (pathSegments.isEmpty) {
      _navigateToHome();
      return;
    }

    final route = pathSegments[0];

    switch (route) {
      case 'profile':
        _handleProfileRoute(pathSegments, queryParams);
        break;
      case 'payment':
        _handlePaymentRoute(pathSegments, queryParams);
        break;
      case 'product':
        _handleProductRoute(pathSegments, queryParams);
        break;
      case 'notification':
        _handleNotificationRoute(pathSegments, queryParams);
        break;
      case 'campaign':
        _handleCampaignRoute(pathSegments, queryParams);
        break;
      default:
        _navigateToHome();
    }
  }

  void _handleProfileRoute(List<String> segments, Map<String, String> params) {
    if (segments.length > 1) {
      final userId = segments[1];
      final tab = params['tab'];
      Navigator.of(_context!).pushNamed(
        '/profile',
        arguments: ProfileArguments(userId: userId, tab: tab),
      );
    } else {
      Navigator.of(_context!).pushNamed('/profile');
    }
  }

  void _handlePaymentRoute(List<String> segments, Map<String, String> params) {
    if (segments.length > 1) {
      final action = segments[1];
      
      switch (action) {
        case 'confirm':
          final transactionId = params['transaction_id'];
          final amount = params['amount'];
          final status = params['status'];
          Navigator.of(_context!).pushNamed(
            '/payment/confirm',
            arguments: PaymentConfirmArguments(
              transactionId: transactionId,
              amount: amount,
              status: status,
            ),
          );
          break;
        case 'history':
          Navigator.of(_context!).pushNamed('/payment/history');
          break;
        case 'add':
          final method = params['method'];
          Navigator.of(_context!).pushNamed(
            '/payment/add',
            arguments: PaymentAddArguments(method: method),
          );
          break;
        default:
          Navigator.of(_context!).pushNamed('/payment');
      }
    } else {
      Navigator.of(_context!).pushNamed('/payment');
    }
  }

  void _handleProductRoute(List<String> segments, Map<String, String> params) {
    if (segments.length > 1) {
      final productId = segments[1];
      final source = params['source'];
      final campaignId = params['campaign_id'];
      Navigator.of(_context!).pushNamed(
        '/product',
        arguments: ProductArguments(
          productId: productId,
          source: source,
          campaignId: campaignId,
        ),
      );
    }
  }

  void _handleNotificationRoute(List<String> segments, Map<String, String> params) {
    final notificationId = params['id'];
    final type = params['type'];
    final data = params['data'];
    
    Navigator.of(_context!).pushNamed(
      '/notification',
      arguments: NotificationArguments(
        notificationId: notificationId,
        type: type,
        data: data,
      ),
    );
  }

  void _handleCampaignRoute(List<String> segments, Map<String, String> params) {
    if (segments.length > 1) {
      final campaignId = segments[1];
      final source = params['source'];
      final medium = params['medium'];
      final content = params['content'];
      
      Navigator.of(_context!).pushNamed(
        '/campaign',
        arguments: CampaignArguments(
          campaignId: campaignId,
          source: source,
          medium: medium,
          content: content,
        ),
      );
    }
  }

  void _navigateToHome() {
    Navigator.of(_context!).pushNamedAndRemoveUntil('/', (route) => false);
  }

  void dispose() {
    _linkSubscription?.cancel();
    _context = null;
  }
}

