class _MyAppState extends State<MyApp> {
  final DeepLinkHandler _deepLinkHandler = DeepLinkHandler();

  @override
  void dispose() {
    _deepLinkHandler.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'Deep Link Demo',
      theme: ThemeData(primarySwatch: Colors.blue),
      initialRoute: '/',
      onGenerateRoute: (settings) {
        WidgetsBinding.instance.addPostFrameCallback((_) {
          _deepLinkHandler.initialize(context);
        });

        switch (settings.name) {
          case '/':
            return MaterialPageRoute(builder: (_) => HomeScreen());
          case '/profile':
            final args = settings.arguments as ProfileArguments?;
            return MaterialPageRoute(
              builder: (_) => ProfileScreen(arguments: args),
            );
          case '/payment':
            return MaterialPageRoute(builder: (_) => PaymentScreen());
          case '/payment/confirm':
            final args = settings.arguments as PaymentConfirmArguments?;
            return MaterialPageRoute(
              builder: (_) => PaymentConfirmScreen(arguments: args),
            );
          case '/payment/history':
            return MaterialPageRoute(builder: (_) => PaymentHistoryScreen());
          case '/payment/add':
            final args = settings.arguments as PaymentAddArguments?;
            return MaterialPageRoute(
              builder: (_) => PaymentAddScreen(arguments: args),
            );
          case '/product':
            final args = settings.arguments as ProductArguments?;
            return MaterialPageRoute(
              builder: (_) => ProductScreen(arguments: args),
            );
          case '/notification':
            final args = settings.arguments as NotificationArguments?;
            return MaterialPageRoute(
              builder: (_) => NotificationScreen(arguments: args),
            );
          case '/campaign':
            final args = settings.arguments as CampaignArguments?;
            return MaterialPageRoute(
              builder: (_) => CampaignScreen(arguments: args),
            );
          default:
            return MaterialPageRoute(builder: (_) => HomeScreen());
        }
      },
    );
  }
}

